// src/pages/gov/DonorsPage.jsx
import { useState, useEffect } from "react";
import { useToast }            from "../../context/ToastContext";
import PageHeader              from "../../components/shared/PageHeader";
import DataTable               from "../../components/shared/DataTable";
import Badge                   from "../../components/shared/Badge";
import { donorApi }            from "../../services/api";

const fmt   = (n) => n?.toLocaleString() ?? "–";
const short = (s) => s?.length > 12 ? s.slice(0, 12) + "…" : s;

export default function DonorsPage() {
  const toast = useToast();
  const [userCert, setUserCert] = useState("");
  const [donors,   setDonors]  = useState([]);
  const [fetching, setFetching] = useState(true);

  const loadDonors = async () => {
    if (!userCert) {
      toast("UserCert is required", "error");
      return;
    }
    setFetching(true);
    try {
      const res = await donorApi.getAll({ userCert });
      setDonors(res.data || []);
    } catch {
      toast("Failed to load donors", "error");
    } finally {
      setFetching(false);
    }
  };

  useEffect(() => {
    setFetching(false);
  }, []);

  return (
    <div>
      <PageHeader title="All Donors" desc="Complete donor registry on the ledger" />
      <div className="card" style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", gap: 12, alignItems: "flex-end", flexWrap: "wrap" }}>
          <div className="form-group" style={{ flex: 1, minWidth: 220 }}>
            <label>User Cert</label>
            <input value={userCert} onChange={(e) => setUserCert(e.target.value)} placeholder="Enter userCert" />
          </div>
          <button className="btn btn-primary" onClick={loadDonors} disabled={fetching}>
            {fetching ? "Loading…" : "Load Donors"}
          </button>
        </div>
      </div>
      <div className="card">
        {fetching ? (
          <p style={{ color: "var(--text-muted)" }}>Loading…</p>
        ) : (
          <DataTable
            columns={[
              { key: "id",     label: "Donor ID", mono: true },
              { key: "name",   label: "Name" },
              { key: "email",  label: "Email" },
              { key: "wallet", label: "Wallet",  mono: true, render: (r) => short(r.wallet) },
              { key: "tokens", label: "Tokens",  render: (r) => <><span className="text-gold">◈</span> {fmt(r.tokens)}</> },
              { key: "org",    label: "Org",     render: (r) => <Badge type="blue">{r.org}</Badge> },
            ]}
            data={donors}
          />
        )}
      </div>
    </div>
  );
}
